import kotlinx.coroutines.testing.*
import kotlinx.coroutines.*
import kotlinx.coroutines.channels.*
import kotlinx.coroutines.flow.*
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

/**
 * Tests for callbackFlow + timeout interaction when the callbackFlow is closed with an exception.
 * See https://github.com/Kotlin/kotlinx.coroutines/issues/3939
 */
class CallbackFlowTimeoutTest : TestBase() {
    @Test
    fun testCallbackFlowCloseWithExceptionAndTimeout() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception", exception.message)
    }

    @Test
    fun testCallbackFlowCloseWithExceptionAndTimeoutWithEmissions() = runTest {
        val collected = mutableListOf<Int>()
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close(IllegalStateException("Test Exception After Emissions"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect { collected.add(it) }
        }
        assertEquals("Test Exception After Emissions", exception.message)
        assertEquals(listOf(1, 2), collected)
    }

    @Test
    fun testCallbackFlowCloseNormallyWithTimeout() = runTest {
        val flow = callbackFlow<Int> {
            send(1)
            send(2)
            close()
        }.timeout(5.seconds)

        val result = flow.toList()
        assertEquals(listOf(1, 2), result)
    }

    @Test
    fun testChannelFlowCloseWithExceptionAndTimeout() = runTest {
        val flow = channelFlow<Int> {
            close(IllegalStateException("Test Exception from channelFlow"))
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception from channelFlow", exception.message)
    }

    @Test
    fun testProduceInCloseWithExceptionAndTimeout() = runTest {
        val flow = flow {
            throw IllegalStateException("Test Exception from produce")
        }.timeout(5.seconds)

        val exception = assertFailsWith<IllegalStateException> {
            flow.collect()
        }
        assertEquals("Test Exception from produce", exception.message)
    }
}
"}

